CREATE OR REPLACE FUNCTION public.handle_manifesto_comment_count()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    -- ➕ Safely add 1
    UPDATE public.manifestos 
    SET comments = COALESCE(comments, 0) + 1 
    WHERE id = NEW.manifesto_id;
    RETURN NEW;
    
  ELSIF TG_OP = 'DELETE' THEN
    -- ➖ Safely subtract 1
    UPDATE public.manifestos 
    SET comments = GREATEST(COALESCE(comments, 0) - 1, 0)
    WHERE id = OLD.manifesto_id;
    RETURN OLD;
  END IF;
  
  RETURN NULL;
END;
$function$


