CREATE OR REPLACE FUNCTION public.sync_tag_counts()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF (TG_OP = 'INSERT') THEN
    -- Update post count
    UPDATE public.channel_posts SET tags_count = tags_count + 1 WHERE id = NEW.post_id;
    -- Update target channel count
    UPDATE public.channels SET tags_count = tags_count + 1 WHERE id = NEW.target_channel_id;
    RETURN NEW;
  ELSIF (TG_OP = 'DELETE') THEN
    UPDATE public.channel_posts SET tags_count = tags_count - 1 WHERE id = OLD.post_id;
    UPDATE public.channels SET tags_count = tags_count - 1 WHERE id = OLD.target_channel_id;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$


