CREATE OR REPLACE FUNCTION public.toggle_channel_post_like(target_post_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  is_liked boolean;
  new_count int;
  target_channel_id uuid;
begin
  -- Check specifically in the channel_post_likes table
  select exists (
    select 1 from channel_post_likes 
    where user_id = auth.uid() and post_id = target_post_id
  ) into is_liked;

  if is_liked then
    delete from channel_post_likes where user_id = auth.uid() and post_id = target_post_id;
    new_count := -1;
  else
    insert into channel_post_likes (user_id, post_id) values (auth.uid(), target_post_id);
    new_count := 1;
  end if;

  update channel_posts set likes = coalesce(likes, 0) + new_count where id = target_post_id
  returning likes, channel_id into new_count, target_channel_id;

  if target_channel_id is not null then
    update channels set likes_count = coalesce(likes_count, 0) + (case when is_liked then -1 else 1 end) where id = target_channel_id;
  end if;

  return json_build_object('is_liked', not is_liked, 'new_likes', new_count);
end;
$function$


CREATE OR REPLACE FUNCTION public.can_user_post_status(chan_id uuid, usr_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  posting_setting text;
  user_role text;
  is_creator boolean;
BEGIN
  -- Get the channel setting and check if the user is the owner
  SELECT allow_status_posting_by, (creator_id = usr_id) 
  INTO posting_setting, is_creator
  FROM public.channels 
  WHERE id = chan_id;

  -- If the user is the channel creator, they can always post
  IF is_creator THEN
    RETURN true;
  END IF;

  -- If the setting is 'all', check if they are at least a member
  IF posting_setting = 'all' THEN
    RETURN EXISTS (
      SELECT 1 FROM public.channel_members 
      WHERE channel_id = chan_id AND user_id = usr_id
    );
  END IF;

  -- If setting is 'admin', check if their role is 'admin' or 'owner'
  IF posting_setting = 'admin' THEN
    SELECT role INTO user_role FROM public.channel_members 
    WHERE channel_id = chan_id AND user_id = usr_id;
    RETURN user_role IN ('admin', 'owner');
  END IF;

  RETURN false;
END;
$function$


